#include <vector>
#include <priority_queue>
#include <climits>

using namespace std;

long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& e : edges) {
        int u = e[0];
        int v = e[1];
        long long cost = e[2];
        adj[u].push_back({v, cost});
    }

    vector<long long> max_min(n, -LLONG_MAX);
    const long long INF = 1e18;
    max_min[0] = INF;

    priority_queue<tuple<long long, long long, int>> pq;
    pq.push({ -INF, 0, 0 });

    while (!pq.empty()) {
        auto [neg_curr_min, total_cost, u] = pq.top();
        pq.pop();
        long long curr_min = -neg_curr_min;

        if (u == n - 1) {
            return curr_min;
        }

        if (curr_min < max_min[u]) {
            continue;
        }

        for (auto [v, cost] : adj[u]) {
            if (!online[v]) {
                continue;
            }
            long long new_total = total_cost + cost;
            if (new_total > k) {
                continue;
            }
            long long new_min = min(curr_min, cost);
            if (new_min > max_min[v]) {
                max_min[v] = new_min;
                pq.push({ -new_min, new_total, v });
            }
        }
    }

    return -1;
}
